 1→import { windowOutlineOnWall, wallDirection, positionOnWall } from '@/geometry/wallGeometry';
 2→import { perpendicular, scale, add } from '@/geometry/point';
 3→
 4→export default function WindowRenderer({ windows, walls }) {
 5→  return (
 6→    <g className="windows">
 7→      {windows.map(win => {
 8→        const wall = walls.find(w => w.id === win.wallId);
 9→        if (!wall) return null;
10→
11→        const info = windowOutlineOnWall(wall, win);
12→        const dir = wallDirection(wall);
13→        const perp = perpendicular(dir);
14→        const halfThick = wall.thickness / 2;
15→
16→        // Three parallel lines across the gap
17→        const lines = [-0.3, 0, 0.3].map(fraction => {
18→          const offset = scale(perp, halfThick * fraction);
19→          return {
20→            x1: add(info.start, offset).x,
21→            y1: add(info.start, offset).y,
22→            x2: add(info.end, offset).x,
23→            y2: add(info.end, offset).y,
24→          };
25→        });
26→
27→        return (
28→          <g key={win.id} data-id={win.id} data-type="window">
29→            {/* White rectangle to mask wall */}
30→            <polygon
31→              points={`${info.p1.x},${info.p1.y} ${info.p2.x},${info.p2.y} ${info.p3.x},${info.p3.y} ${info.p4.x},${info.p4.y}`}
32→              fill="white"
33→              stroke="none"
34→            />
35→            {/* Window parallel lines */}
36→            {lines.map((l, i) => (
37→              <line
38→                key={i}
39→                x1={l.x1} y1={l.y1}
40→                x2={l.x2} y2={l.y2}
41→                stroke="var(--color-wall-fill)"
42→                strokeWidth={i === 1 ? 2 : 1}
43→                vectorEffect="non-scaling-stroke"
44→              />
45→            ))}
46→          </g>
47→        );
48→      })}
49→    </g>
50→  );
51→}
